function getAccountNumber(selectedAccountNumber) {
    const accountList = Context.getVariable("account_list").accounts;
    const last4 = String(selectedAccountNumber).slice(-4);
    const account = accountList.find(acc => acc.account_number.endsWith(last4));
    if (!account) return null;
    // return account.account_number;
    return {
    "account_number": account.account_number,
    "account_balance": account.balance
  }
}

const origin_account = getAccountNumber(Context.getVariable("selected_origin_account_number"));
if (!origin_account){
    Context.setVariable('is_valid_transfer', false);
    Context.setVariable('workflow_status', "ORIGIN_ACCOUNT_NOT_FOUND");
}else{
    const origin_account_number = origin_account.account_number;
    const origin_account_balance = origin_account.account_balance;
    Context.setVariable('origin_account_number', origin_account_number);
    Context.setVariable('origin_account_balance', origin_account_balance);
    const transfer_amount = Context.getVariable("transfer_value");
    if (Number(origin_account_balance) < Number(transfer_amount)) {
        Context.setVariable('is_valid_transfer', false);
        Context.setVariable('workflow_status', "INSUFFICIENT_FUNDS");
    } else {
        Context.setVariable('is_valid_transfer', true); 
    }
}

